#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
LL p,n;
bool flag;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
LL QP(LL x,LL y,LL mod){
    LL as=1;
    while(y){
        if(y&1)as=as*x%mod;
        x=x*x%mod,y>>=1;
    }return as;
}
int main(){
    cin>>p>>n;
    if(QP(n,(p-1)/2,p)==1)flag=1;
    LL mid=(p-1)/2;
    cout<<p-1<<" 0\n";
    fflush(stdout);
    for(int i=1;i<=mid;i++){
        LL id,x;cin>>id>>x;
        LL nid=(id>=mid?id-mid:id+mid);
        LL nx=(flag?n-x-1:x);
        cout<<nid<<" "<<nx<<"\n";
        fflush(stdout);
    }
    return 0;
}
